	t.Run("draftで著者本人は受講可能", func(t *testing.T) {
		course := Course{publishStatus: "draft", author: Author{authorId: "author-1"}}
		if err := course.checkEnrollable("author-1"); err != nil {
			t.Errorf("エラーが発生しないこと: %v", err)
		}
	})

	t.Run("draftで非著者はErrEnrollmentNotAllowedを返す", func(t *testing.T) {
		course := Course{publishStatus: "draft", author: Author{authorId: "author-1"}}
		if err := course.checkEnrollable("user-1"); !errors.Is(err, ErrEnrollmentNotAllowed) {
			t.Errorf("ErrEnrollmentNotAllowedが返ること: got %v", err)
		}
	})
}

